form:Form.form:Scripts:
		function Guardar()
{  	  
	FillArray(100);
	Ctrl("main").DoEvent("SAVE");
}                          


function ONLOAD()
{
	var t, ROW, VALUES;
	arrFILTER = new Array();
	arrSELECTED = new Array();

	//Valores Iniciales
	for (t=0; t<Ctrl("arrSELECTED").CountRow(); t++)
	{
		ROW=Ctrl("arrSELECTED").GetRow(t);
		VALUES=ROW.GetAttr("VALUES").split(",");
		for (d=0; d<VALUES.length; d++)
		if (VALUES[d]!="") arrSELECTED.push(VALUES[d]);
	} 

	refreshSelected();
	refreshList();    

	if(!Ctrl('img_ojo').GetEnabled())
	{
		//cargar solo los legajos que son no confidenciales
		Ctrl('l_confidencial').SetXValue('0');
	}   
	else
	{        
		if(Ctrl('liq_confidencial').GetXValue() =='0')
		{   
			Ctrl('l_confidencial').SetXValue('0');
		}
		else
		{
		   	Ctrl('l_confidencial').SetXValue('1');
		}
	}

	//Debug
	//if(Ctrl('empresa').GetXValue() == "") Ctrl('empresa').SetXValue("1");
	//if(Ctrl('liquidacion').GetXValue() == "") Ctrl('liquidacion').SetXValue("5");

	//Obtengo la informacion adicional para el filtro de legajos
	if(Ctrl('liquidacion').GetXValue())
	{                                         
	  var	np = GetProxy();
		var nSQL = np.SQLService(); 	
		var qry = Ctrl("main").getResource("qry_info_externo");	 

		var result = nSQL.GetXML(qry, "<PARAM liquidacion=\""+Ctrl('liquidacion').GetXValue()+"\" />");
	 	var where = "";
	 	var sep = "";

		if (result.GetAttr("c_tipo_liq") == "1")
		{
			if (result.GetAttr("c_clase") == "M")
			{                                    
				where += sep + "LEG.oi_tipo_personal in ("+result.FindElement2("TPER", "c_tipo_personal","1").GetAttr("oi_tipo_personal")+","+result.FindElement2("TPER", "c_tipo_personal","4").GetAttr("oi_tipo_personal")+","+result.FindElement2("TPER", "c_tipo_personal","8").GetAttr("oi_tipo_personal")+","+result.FindElement2("TPER", "c_tipo_personal","3").GetAttr("oi_tipo_personal")+")";
				sep = " AND ";
			} 
			else if (result.GetAttr("c_clase") == "Q")
			{
				where += sep + "LEG.oi_tipo_personal in ("+result.FindElement2("TPER", "c_tipo_personal","2").GetAttr("oi_tipo_personal")+","+result.FindElement2("TPER", "c_tipo_personal","5").GetAttr("oi_tipo_personal")+")";
				sep = " AND ";

				if (result.GetAttr("e_quincena") == "1")
				{
					where += sep + "LEG.f_ingreso < {datetime(\\'" + result.GetAttr("e_fecha3") + "\\')}";
					sep = " AND ";
				}
				else if (result.GetAttr("e_quincena") == "2")
				{
					where += sep + "(ISNULL(LEG.f_egreso) OR LEG.f_egreso >= {datetime(\\'" + result.GetAttr("e_fecha3") + "\\')})";
					sep = " AND ";
				}
			}		
		}  

		if (result.GetAttr("c_tipo_liq") == "3")
		{
			where += sep + "ISNOTNULL(LEG.f_egreso) AND LEG.f_egreso >= {datetime(\\'" + result.GetAttr("e_fecha1")+ "\\')} AND LEG.f_egreso < {datetime(\\'" + result.GetAttr("e_fecha2")+ "\\')}";
			sep = " AND ";
		}
		else
		{
			if (result.GetAttr("l_egresados") != "1")
			{
				where += sep + "(ISNULL(LEG.f_egreso) OR LEG.f_egreso >= {datetime(\\'" + result.GetAttr("e_fecha2")+ "\\')}) AND LEG.oi_indic_activo != 10 ";
				sep = " AND ";
			} 
			else
			{
				where += sep + "(ISNULL(LEG.f_egreso) OR LEG.f_egreso >= {datetime(\\'" + result.GetAttr("e_fecha1")+ "\\')})";
				sep = " AND ";
			}
		}

		//if (result.GetAttr("c_tipo_liq") != "6")
		//{
			where += sep + "LEG.f_ingreso < {datetime(\\'" + result.GetAttr("e_fecha2")+ "\\')}";
			sep = " AND ";
		//}

		if (Ctrl('l_confidencial').GetXValue() != "1")
		{
			where += sep + "LEG.l_confidencial = 0";
		}

		Ctrl('where').SetXValue(where);
	} 
}
